import { useMemo } from 'react'
import { useTransition, animated, to, SpringValue } from '@react-spring/web'
import { useMotionConfig, PropertyAccessor, usePropertyAccessor } from '@nivo/core'
import { useTheme } from '@nivo/theming'
import { useInheritedColor, InheritedColorConfig } from '@nivo/colors'
import { ComputedDatum, DatumId } from './types'

interface ComputedRadialLabel {
    id: DatumId
    x: number
    y: number
    rotation: number
    label: string
    color: string
}

interface AnimatedLabelProps {
    x: SpringValue<number>
    y: SpringValue<number>
    rotation: SpringValue<number>
    opacity: SpringValue<number>
}

interface RadialLabelsLayerProps<RawDatum> {
    center: [number, number]
    data: ComputedDatum<RawDatum>[]
    label: PropertyAccessor<ComputedDatum<RawDatum>, DatumId>
    skipAngle: number
    skipRadius: number
    radiusOffset: number
    textColor: InheritedColorConfig<ComputedDatum<RawDatum>>
    rotation: number
}

export const RadialLabelsLayer = <RawDatum,>({
    center,
    data,
    label,
    skipAngle,
    skipRadius,
    radiusOffset,
    textColor,
    rotation: extraRotation,
}: RadialLabelsLayerProps<RawDatum>) => {
    const theme = useTheme()
    const { animate, config: springConfig } = useMotionConfig()
    const getTextColor = useInheritedColor(textColor, theme)
    const getLabel = usePropertyAccessor<ComputedDatum<RawDatum>, DatumId>(label)

    const fontSize = (theme.labels?.text?.fontSize as number) || 11
    const textHeight = fontSize * 1.2
    const padding = 4 // padding in pixels

    // bigger numbers, less letters will be visible
    const CHAR_WIDTH_UPPER = 0.74
    const CHAR_WIDTH_OTHER = 0.6

    const HORIZONTAL_SNAP_RANGE = 5 // degrees around 90°/270° to snap text horizontal
    const MIN_TRUNCATED_CHARS = 2 // minimum visible chars before ellipsis

    // Pre-compute all label positions and text, always using vertical (radial) orientation
    const labels = useMemo(() => {
        const getStringWidth = (str: string) => {
            let total = 0
            for (const ch of str) {
                total += (ch >= 'A' && ch <= 'Z' ? CHAR_WIDTH_UPPER : CHAR_WIDTH_OTHER) * fontSize
            }
            return total
        }

        const result: ComputedRadialLabel[] = []

        for (const datum of data) {
            const { arc } = datum
            const angleDeg = ((arc.endAngle - arc.startAngle) * 180) / Math.PI

            if (angleDeg < skipAngle) continue

            const thickness = arc.outerRadius - arc.innerRadius
            if (thickness < skipRadius) continue

            const midAngle = (arc.startAngle + arc.endAngle) / 2
            const midRadius = arc.innerRadius + (arc.outerRadius - arc.innerRadius) * radiusOffset

            const x = midRadius * Math.sin(midAngle)
            const y = -midRadius * Math.cos(midAngle)

            const labelText = getLabel(datum)
            const fullLabel = String(labelText)

            const arcLength = midRadius * (arc.endAngle - arc.startAngle)

            let rotation = (midAngle * 180) / Math.PI - 90 + extraRotation

            // Flip text when it would read downward
            const normalizedRotation = ((rotation % 360) + 360) % 360
            if (normalizedRotation > 90 && normalizedRotation < 270) {
                rotation += 180
            }

            // Snap to horizontal when text is nearly vertical (±HORIZONTAL_SNAP_RANGE° around 90°/270°)
            const finalNormalized = ((rotation % 360) + 360) % 360
            const isHorizontal =
                (finalNormalized >= 90 - HORIZONTAL_SNAP_RANGE &&
                    finalNormalized <= 90 + HORIZONTAL_SNAP_RANGE) ||
                (finalNormalized >= 270 - HORIZONTAL_SNAP_RANGE &&
                    finalNormalized <= 270 + HORIZONTAL_SNAP_RANGE)
            if (isHorizontal) {
                rotation = 0
            }

            // For horizontal text: width is limited by arc length, height by thickness.
            // For radial text: width is limited by thickness, height by arc length.
            const availableWidth = isHorizontal
                ? arcLength >= textHeight + padding
                    ? arcLength - padding * 2
                    : 0
                : arcLength >= textHeight + padding
                  ? thickness - padding * 2
                  : 0

            if (availableWidth <= 0) continue

            let displayLabel: string

            if (getStringWidth(fullLabel) <= availableWidth) {
                displayLabel = fullLabel
            } else {
                const ellipsisWidth = getStringWidth('\u2026')
                let end = 0
                while (
                    end < fullLabel.length &&
                    getStringWidth(fullLabel.slice(0, end + 1)) + ellipsisWidth <= availableWidth
                ) {
                    end++
                }
                if (end < MIN_TRUNCATED_CHARS) continue
                displayLabel = fullLabel.slice(0, end) + '\u2026'
            }

            const color = getTextColor(datum)

            result.push({ id: datum.id, x, y, rotation, label: displayLabel, color })
        }

        return result
    }, [
        data,
        skipAngle,
        skipRadius,
        radiusOffset,
        extraRotation,
        fontSize,
        textHeight,
        getLabel,
        getTextColor,
    ])

    // Animate labels with react-spring
    const transition = useTransition<ComputedRadialLabel, AnimatedLabelProps>(labels, {
        keys: (item: ComputedRadialLabel) => item.id,
        from: (item: ComputedRadialLabel) => ({
            x: 0,
            y: 0,
            rotation: item.rotation,
            opacity: 0,
        }),
        enter: (item: ComputedRadialLabel) => ({
            x: item.x,
            y: item.y,
            rotation: item.rotation,
            opacity: 1,
        }),
        update: (item: ComputedRadialLabel) => ({
            x: item.x,
            y: item.y,
            rotation: item.rotation,
            opacity: 1,
        }),
        leave: {
            opacity: 0,
        },
        config: springConfig,
        immediate: !animate,
    })

    return (
        <g transform={`translate(${center[0]}, ${center[1]})`}>
            {transition((style, item) => (
                <animated.text
                    key={String(item.id)}
                    transform={to(
                        [style.x, style.y, style.rotation],
                        (xi, yi, ri) => `translate(${xi}, ${yi}) rotate(${ri})`
                    )}
                    textAnchor="middle"
                    dominantBaseline="central"
                    opacity={style.opacity}
                    style={{
                        ...theme.labels.text,
                        fill: item.color,
                        pointerEvents: 'none',
                        userSelect: 'none',
                    }}
                >
                    {item.label}
                </animated.text>
            ))}
        </g>
    )
}
